// src/data/experience.js
// ─────────────────────────────────────────────────────────
// Work experience and education timeline data.
// Update dates, roles, and descriptions to match your own.
// ─────────────────────────────────────────────────────────

export const WORK_EXPERIENCE = [
  {
    date: "JULY-2024 ",
    role: "Full Stack Developer (Fresher)",
    org: "Open to Opportunities",
    desc: "Actively building portfolio projects, contributing to open source, and seeking a full-time MERN stack role in a dynamic team.",
    accentColor: "var(--accent)",
  },
  {
    date: "2023 — 2024",
    role: "Freelance Web Developer",
    org: "Self-Employed",
    desc: "Built and deployed multiple client websites and web apps using React and Node.js. Handled everything from UI design to database design and hosting.",
    accentColor: "var(--accent)",
  },
  {
    date: "2023",
    role: "Web Dev Intern",
    org: "Startup / Organization",
    desc: "Worked on React frontend components, REST API integration, and bug fixes. Collaborated with a small agile team using Git workflows.",
    accentColor: "var(--accent)",
  },
];

export const EDUCATION = [
  {
    date: "2020 – 2024",
    role: "B.Tech in Computer Science",
    org: "University / College Name",
    desc: "Focused on Data Structures, Algorithms, Database Systems, and Software Engineering. Built multiple capstone projects.",
    accentColor: "var(--accent2)",
  },
  {
    date: "2023",
    role: "MERN Stack Bootcamp",
    org: "Online Certification",
    desc: "Intensive 6-month program covering React, Node.js, MongoDB, Express and deployment to cloud platforms.",
    accentColor: "var(--accent2)",
  },
];
